1	/**
2	 * IDE Skill Installer — Verbatim skill directory installation
3	 *
4	 * Replaces the legacy command-file generation approach with the BMAD standard:
5	 * skill directories (containing SKILL.md + supporting files) are copied directly
6	 * to each IDE's skills/ directory. IDEs read SKILL.md natively.
7	 *
8	 * Supports 23+ IDEs via platform-codes.yaml (config-driven, no IDE-specific code).
9	 */
10	
11	const path = require('node:path');
12	const fs = require('fs-extra');
13	const yaml = require('js-yaml');
14	
15	const PLATFORM_CODES_PATH = path.join(__dirname, 'platform-codes.yaml');
16	
17	// OS/editor artifacts to filter during copy
18	const ARTIFACT_FILTER = new Set(['.DS_Store', 'Thumbs.db', 'desktop.ini', '._.DS_Store']);
19	
20	/**
21	 * Load platform configuration from platform-codes.yaml.
22	 * Returns { platforms: { 'claude-code': { name, preferred, installer: { target_dir, legacy_targets } }, ... } }
23	 */
24	function loadPlatforms() {
25	  const content = fs.readFileSync(PLATFORM_CODES_PATH, 'utf8');
26	  return yaml.load(content);
27	}
28	
29	/**
30	 * Get available platforms for UI display.
31	 * Returns array of { value: 'claude-code', label: 'Claude Code', preferred: true }
32	 */
33	function getAvailablePlatforms() {
34	  const config = loadPlatforms();
35	  return Object.entries(config.platforms)
36	    .filter(([, p]) => !p.suspended)
37	    .map(([code, p]) => ({
38	      value: code,
39	      label: p.name,
40	      preferred: p.preferred || false,
41	    }))
42	    .sort((a, b) => {
43	      // Preferred first, then alphabetical
44	      if (a.preferred !== b.preferred) return b.preferred ? 1 : -1;
45	      return a.label.localeCompare(b.label);
46	    });
47	}
48	
49	/**
50	 * Get IDE auto-detection markers.
51	 * Returns { 'claude-code': ['.claude'], 'cursor': ['.cursor'], ... }
52	 */
53	function getDetectionMarkers() {
54	  const config = loadPlatforms();
55	  const markers = {};
56	  for (const [code, p] of Object.entries(config.platforms)) {
57	    if (p.suspended) continue;
58	    const targetDir = p.installer?.target_dir;
59	    if (!targetDir) continue;
60	    // Use the top-level directory of the target as the detection marker
61	    const topDir = '.' + targetDir.split('/')[0].replace(/^\./, '');
62	    markers[code] = [topDir];
63	  }
64	  return markers;
65	}
66	
67	/**
68	 * Install skill directories to all selected IDEs.
69	 *
70	 * @param {string} projectDir - Project root directory
71	 * @param {string} skfDir - Path to installed SKF module (e.g., {projectDir}/_bmad/skf)
72	 * @param {string[]} ideCodes - Array of IDE codes (e.g., ['claude-code', 'cursor'])
73	 * @returns {{ installed: number, ides: string[], directories: string[] }}
74	 */
75	async function installSkillsToIdes(projectDir, skfDir, ideCodes) {
76	  if (!ideCodes || ideCodes.length === 0) return { installed: 0, ides: [], directories: [] };
77	
78	  const config = loadPlatforms();
79	  let totalInstalled = 0;
80	  const processedIdes = [];
81	  const allDirectories = [];
82	
83	  // Copy filter: skip OS artifacts
84	  const copyFilter = (src) => !ARTIFACT_FILTER.has(path.basename(src));
85	
86	  for (const ideCode of ideCodes) {
87	    const platform = config.platforms[ideCode];
88	    if (!platform || !platform.installer?.target_dir) continue;
89	
90	    const targetDir = path.join(projectDir, platform.installer.target_dir);
91	
92	    // Clean legacy targets first (old command files from previous SKF installs)
93	    await cleanLegacyTargets(projectDir, platform);
94	
95	    // Clean existing SKF skills from this IDE (for update/reinstall)
96	    await cleanSkfSkills(targetDir);
97	
98	    // Ensure target directory exists
99	    await fs.ensureDir(targetDir);
100	
101	    // Copy all skf-* skill directories from the installed module
102	    if (await fs.pathExists(skfDir)) {
103	      const entries = await fs.readdir(skfDir, { withFileTypes: true });
104	      for (const entry of entries) {
105	        if (!entry.isDirectory()) continue;
106	
107	        // Copy skill directories (skf-*) and supporting resources (knowledge/, shared/)
108	        if (entry.name.startsWith('skf-') || entry.name === 'knowledge' || entry.name === 'shared') {
109	          const src = path.join(skfDir, entry.name);
110	          const dest = path.join(targetDir, entry.name);
111	          await fs.copy(src, dest, { filter: copyFilter });
112	          totalInstalled++;
113	        }
114	      }
115	    }
116	
117	    // Also copy the agent skill from source (not in _bmad/skf/ since copySrcFiles includes it now)
118	    const agentSrc = path.join(skfDir, 'skf-forger');
119	    if (await fs.pathExists(agentSrc)) {
120	      // Already copied above via the skf-* loop
121	    }
122	
123	    allDirectories.push(platform.installer.target_dir);
124	    processedIdes.push(ideCode);
125	  }
126	
127	  return { installed: totalInstalled, ides: processedIdes, directories: allDirectories };
128	}
129	
130	/**
131	 * Remove legacy command files from old IDE target directories.
132	 * Handles migration from command-file approach to skill-directory approach.
133	 */
134	async function cleanLegacyTargets(projectDir, platform) {
135	  const legacyTargets = platform.installer?.legacy_targets || [];
136	
137	  for (const legacyDir of legacyTargets) {
138	    const fullPath = path.join(projectDir, legacyDir);
139	    if (!(await fs.pathExists(fullPath))) continue;
140	
141	    try {
142	      const files = await fs.readdir(fullPath);
143	      for (const file of files) {
144	        // Remove SKF-specific command files from legacy directories
145	        if (file.startsWith('bmad-skf-') || file.startsWith('bmad-agent-skf-')) {
146	          await fs.remove(path.join(fullPath, file));
147	        }
148	      }
149	
150	      // Remove empty directories
151	      const remaining = await fs.readdir(fullPath);
152	      if (remaining.length === 0) {
153	        await fs.remove(fullPath);
154	        // Also try to remove empty parent
155	        const parentDir = path.dirname(fullPath);
156	        try {
157	          const parentRemaining = await fs.readdir(parentDir);
158	          if (parentRemaining.length === 0) await fs.remove(parentDir);
159	        } catch {
160	          /* ignore */
161	        }
162	      }
163	    } catch {
164	      /* non-critical, continue */
165	    }
166	  }
167	}
168	
169	/**
170	 * Remove existing SKF skill directories from an IDE target.
171	 * Called before reinstalling to ensure clean state.
172	 */
173	async function cleanSkfSkills(targetDir) {
174	  if (!(await fs.pathExists(targetDir))) return;
175	
176	  try {
177	    const entries = await fs.readdir(targetDir);
178	    for (const entry of entries) {
179	      // Only remove SKF-owned directories (skf-*, knowledge, shared)
180	      if (entry.startsWith('skf-') || entry === 'knowledge' || entry === 'shared') {
181	        await fs.remove(path.join(targetDir, entry));
182	      }
183	    }
184	  } catch {
185	    /* non-critical */
186	  }
187	}
188	
189	/**
190	 * Remove all SKF skills from all known IDE directories.
191	 * Used during uninstall.
192	 */
193	async function removeAllSkfSkills(projectDir) {
194	  const config = loadPlatforms();
195	  const removed = [];
196	
197	  for (const [, platform] of Object.entries(config.platforms)) {
198	    if (!platform.installer?.target_dir) continue;
199	    const targetDir = path.join(projectDir, platform.installer.target_dir);
200	    if (await fs.pathExists(targetDir)) {
201	      await cleanSkfSkills(targetDir);
202	      // Also clean legacy targets
203	      await cleanLegacyTargets(projectDir, platform);
204	      removed.push(platform.installer.target_dir);
205	    }
206	  }
207	
208	  return removed;
209	}
210	
211	module.exports = { installSkillsToIdes, getAvailablePlatforms, getDetectionMarkers, removeAllSkfSkills, loadPlatforms };
212	
